import tw from 'twin.macro'
import { graphql, HeadFC, useStaticQuery } from 'gatsby'
import * as React from 'react'
import { GatsbyImage, getImage } from 'gatsby-plugin-image'
import styled from '@emotion/styled'
import Layout from '../components/layout'
import Seo from '../components/seo'

interface ImageQuery {}

const mainContributors = [
  {
    name: 'johnny kim',
    github: 'https://github.com/johnny-mh',
    blog: 'https://johnny-mh.github.io/',
    desc: '<a href="https://johnny-mh.github.io/" target="_blank" rel="noopener">johnny kim</a>은 카카오에서 프론트엔드 개발자로 근무하고 있습니다. 선물하기, 쇼핑하기, 프렌즈샵, 내부 백 오피스 웹 앱들을 위한 공통 Angular 모듈들과 Node.js 기반 웹 서버 및 CLI 도구들을 개발하는 팀을 이끌고 있습니다.',
  },
]

const subContributors = [
  {
    name: 'johnny kim',
    github: 'https://github.com/johnny-mh',
    blog: 'https://johnny-mh.github.io/',
  },
  {
    name: 'harrison ford',
    github: 'https://github.com/akh9804',
    blog: 'https://akh9804.github.io/',
  },
  {
    name: 'daisy jeong',
    github: 'https://github.com/gguljeong',
    blog: 'https://gguldh.tistory.com/',
  },
  {
    name: 'jaeseo kim',
    github: 'https://github.com/JaeSeoKim',
    blog: 'https://jaeseokim.dev',
  },
]

interface AboutPageProps {}

const AboutPage: React.FC<AboutPageProps> = () => {
  const {
    allFile: { nodes },
  } = useStaticQuery<{
    allFile: { nodes: { name: string; childImageSharp: any }[] }
  }>(graphql`
    query {
      allFile(
        filter: {
          dir: { regex: "/src/images$/" }
          name: { regex: "/^profile/" }
        }
      ) {
        nodes {
          name
          childImageSharp {
            gatsbyImageData(width: 160, height: 160, placeholder: NONE)
          }
        }
      }
    }
  `)

  return (
    <Layout>
      <StyledAbout>
        <div tw="flex flex-wrap items-center justify-between overflow-hidden">
          <div tw="text-center md:text-left w-full md: max-w-xl">
            <h1 tw="mb-4 text-5xl font-bold">About</h1>
          </div>
        </div>
        <div className="youtube-container">
          <iframe
            src="https://www.youtube.com/embed/gc4_gS64K1Q"
            title="YouTube video player"
            frameBorder="0"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          />
        </div>
        <aside tw="p-5 bg-orange-50 rounded">
          📜 소개 페이지:{' '}
          <a
            href="https://www.patterns.dev/about/"
            target="_blank"
            rel="noreferrer"
          >
            patterns.dev - about
          </a>
        </aside>
        <p>
          <a href="https://www.patterns.dev/" target="_blank" rel="noreferrer">
            patterns.dev
          </a>
          는{' '}
          <a
            href="https://www.theavocoder.com/"
            target="_blank"
            rel="noreferrer"
          >
            Lydia Hallie
          </a>
          과{' '}
          <a href="https://addyosmani.com/" target="_blank" rel="noreferrer">
            Addy Osmani
          </a>
          가 자바스크립트의 디자인 패턴, 렌더링 패턴, 성능 패턴에 대한 현대적인
          관점들을 제공하기 위해 작성하고 공유한 책입니다.
        </p>
        <p>
          책의 내용에 따르면 저의 경험은 실무적으로는 클라이언트 사이드 렌더링 -
          서버사이드 렌더링에서 멈추었고. 그나마 이 프로젝트를 포함한 개인
          프로젝트에서 정적 렌더링을 사용하기 시작했습니다.
        </p>
        <p>
          글을 읽으며 아직도 공부해야 할 것이 정말 많다는 것을 절실히
          느꼈습니다. 특히나 zero bundle size를 목표로 진행중인 react server
          components나 기타 조금이라도 불필요한 스크립트를 줄이기 위한 렌더링
          패턴들은 느슨했던 저의 커리어에 넘치는 긴장감을 주었고 번역 해 보기로
          한 계기가 되었습니다.
        </p>
        <p>
          이 글을 읽으시는 분들에게도 도움이 되었으면 좋겠습니다. 피드백은 글의
          상단에 있는 &quot;피드백 전송&quot; 기능을 통해 보내주시면. 확인하여
          반영토록 하겠습니다.
        </p>
        <p>한국어 번역과 사이트 게시를 허락해준 Addy에게 감사를 표합니다!</p>

        <hr />

        <h2 tw="text-3xl font-bold mt-16 mb-10">번역 및 검수</h2>

        <div tw="mb-28">
          {mainContributors.map(obj => {
            const img = nodes.find(
              node => node.name === `profile_${obj.name.replace(/[^a-z]/g, '')}`
            )

            if (!img) {
              return null
            }

            return (
              <div
                key={obj.name}
                tw="flex justify-start items-center gap-4 mb-2"
              >
                <div>
                  <GatsbyImage
                    image={getImage(img)!}
                    alt={obj.name}
                    imgStyle={{
                      borderRadius: '15px',
                      border: '1px solid #eee',
                    }}
                    tw="w-36 h-36"
                  />
                </div>
                <div tw="flex flex-col justify-center items-start">
                  <h3 tw="font-bold mb-2 text-xl">{obj.name}</h3>
                  <div dangerouslySetInnerHTML={{ __html: obj.desc }} />
                </div>
              </div>
            )
          })}
        </div>

        <div tw="grid grid-cols-1 gap-y-8 md:grid-cols-2">
          {subContributors.map(obj => {
            const img = nodes.find(
              node => node.name === `profile_${obj.name.replace(/[^a-z]/g, '')}`
            )

            if (!img) {
              return null
            }

            return (
              <div
                key={obj.name}
                tw="flex justify-start items-center gap-4 mb-2 mx-2"
              >
                <GatsbyImage
                  image={getImage(img)!}
                  alt={obj.name}
                  imgStyle={{
                    borderRadius: '50%',
                    border: '1px solid #eee',
                  }}
                  tw="w-32 h-32"
                />
                <div tw="flex flex-col justify-center items-start">
                  <h3 tw="font-bold mb-2 text-lg">{obj.name}</h3>
                  <ul tw="mb-2">
                    <li>
                      <a href={obj.github} target="_blank" rel="noreferrer">
                        github
                      </a>
                    </li>
                    <li>
                      <a href={obj.blog} target="_blank" rel="noreferrer">
                        blog
                      </a>
                    </li>
                  </ul>
                </div>
              </div>
            )
          })}
        </div>
      </StyledAbout>
    </Layout>
  )
}

/* eslint-disable react/prop-types */
export const Head: HeadFC = () => <Seo pathname="/about" title="About" />
/* eslint-enable react/prop-types */

export default AboutPage

const StyledAbout = styled.div`
  ${tw`pt-20`}

  p, aside, .youtube-container {
    ${tw`mb-8`}
  }

  .youtube-container {
    position: relative;
    padding-bottom: 56.25%;
    height: 0;
    overflow: hidden;
  }

  .youtube-container iframe {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
  }
`
